import { useState } from 'react';

import Login from './components/auth/Login';
import Signup from './components/auth/Signup';

import AdminLayout from './components/l/AdminDashboard';
import TechnicianDashboard from './components/dashboards/TechnicianDashboard';
import UserDashboard from './components/dashboards/UserDashboard';

function App() {
  const [page, setPage] = useState('login');
  const [isAuth, setIsAuth] = useState(false);
  const [userRole, setUserRole] = useState(null);
  const [userData, setUserData] = useState(null);

  const loginSuccess = (role, email) => {
    setIsAuth(true);
    setUserRole(role);
    setUserData({ role, email });
  };

  const signupSuccess = (data) => {
    setIsAuth(true);
    setUserRole(data.role);
    setUserData(data);
  };

  const logout = () => {
    setIsAuth(false);
    setUserRole(null);
    setUserData(null);
    setPage('login');
  };

  if (!isAuth) {
    return page === 'login' ? (
      <Login onLoginSuccess={loginSuccess} goToSignup={() => setPage('signup')} />
    ) : (
      <Signup onSignupSuccess={signupSuccess} goToLogin={() => setPage('login')} />
    );
  }

  if (userRole === 'admin') return <AdminDashboard userData={userData} onLogout={logout} />;
  if (userRole === 'technician') return <TechnicianDashboard userData={userData} onLogout={logout} />;
  return <UserDashboard userData={userData} onLogout={logout} />;
}

export default App;
